#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        string s;        cin>>s;        ll q;        cin>>q;        ll tot=0;        ll n=s.size();        for(int i=0;i<n-3;i++){            if(s[i]=='1' && s[i+1]=='1' && s[i+2]=='0' && s[i+3]=='0') tot++;        }        while(q--){            ll idx,val;            cin>>idx>>val;            idx--;            bool f=false;            ll old=s[idx]-'0';            for(int i=max(0LL,idx-3);i<=min(n-4,idx);i++){                if(s[i]=='1' && s[i+1]=='1' && s[i+2]=='0' && s[i+3]=='0') {                    tot--;                }            }            s[idx]=val+'0';            for(int i=max(0LL,idx-3);i<=min(n-4,idx);i++){                if(s[i]=='1' && s[i+1]=='1' && s[i+2]=='0' && s[i+3]=='0') {                    tot++;                }            }            if(tot>0){                cout<<"YES"<<endl;            }            else{                cout<<"NO"<<endl;            }        }    }}